import React, { useState } from 'react';
import { Tips, Button } from '@orderly.network/ui';

/**
 * Standard Tips Component
 * Allows users to dismiss the notification.
 */
export const StandardTips = () => {
  const [isVisible, setIsVisible] = useState(true);

  const handleDismiss = () => {
    setIsVisible(false);
    // Optional: Save preference to local storage
    localStorage.setItem('tip_dismissed', 'true');
  };

  if (!isVisible) return null;

  return (
    <div className="relative w-full max-w-md mx-auto mt-4">
      <Tips
        title="New Feature Alert"
        message="Try the new limit order type for better execution."
        variant="success"
        onClose={handleDismiss}
        actionButton={
          <Button size="sm" onClick={handleDismiss}>
            Got it
          </Button>
        }
      />
    </div>
  );
};

export default StandardTips;

import React, { useEffect, useState } from 'react';
import { Tips } from '@orderly.network/ui';
import { useWSObserver } from '@orderly.network/hooks';

/**
 * Advanced Tips Component
 * Listens for real-time system updates via WebSocket.
 */
export const AdvancedTips = () => {
  const [activeTip, setActiveTip] = useState(null);
  const [loading, setLoading] = useState(true);

  // Subscribe to system notifications channel
  const { data } = useWSObserver({
    channel: 'system_notifications',
    enabled: true
  });

  useEffect(() => {
    if (data && data.length > 0) {
      setActiveTip(data[0]);
    }
    setLoading(false);
  }, [data]);

  if (loading) return <div>Loading tips...</div>;
  if (!activeTip) return null;

  return (
    <div className="fixed top-4 right-4 z-50 w-80">
      <Tips
        title={activeTip.title}
        message={activeTip.message}
        variant={activeTip.severity || 'info'}
        timestamp={activeTip.created_at}
        onDismiss={() => setActiveTip(null)}
      />
    </div>
  );
};

export default AdvancedTips;

