import React from 'react';
import { LTVRiskTooltipWidget } from '@orderly.network/ui-order-entry';
import { usePortfolio } from '@orderly.network/hooks';

/**
 * Standard LTV Widget
 * Calculates risk based on current portfolio.
 */
export const StandardLTV = ({ symbol }) => {
  const { data: portfolio } = usePortfolio({ symbol });

  const calculateLTV = () => {
    if (!portfolio) return 0;
    const debt = portfolio.totalDebt || 0;
    const equity = portfolio.totalEquity || 1;
    return Math.min(debt / equity, 1);
  };

  const ltv = calculateLTV();
  const status = ltv > 0.8 ? 'danger' : ltv > 0.5 ? 'warning' : 'safe';

  return (
    <div className="flex items-center gap-2">
      <span className="text-xs text-gray-500">LTV:</span>
      <LTVRiskTooltipWidget
        ltv={ltv}
        status={status}
        symbol={symbol}
        showDetails={true}
      />
    </div>
  );
};

export default StandardLTV;

import React, { useMemo } from 'react';
import { LTVRiskTooltipWidget, Tooltip } from '@orderly.network/ui-order-entry';
import { useAccountInfo, useMarginModeBySymbol } from '@orderly.network/hooks';

/**
 * Advanced LTV Widget
 * Integrates margin modes and liquidation estimates.
 */
export const AdvancedLTV = ({ symbol, positionSize }) => {
  const { data: account } = useAccountInfo();
  const { data: marginMode } = useMarginModeBySymbol({ symbol });

  const riskData = useMemo(() => {
    if (!account || !positionSize) return null;

    const isCross = marginMode === 'cross';
    const liqPrice = isCross 
      ? account.crossLiqPrice 
      : account.isolatedLiqPrice;

    return {
      ltv: account.currentLTV,
      liqPrice,
      marginMode: isCross ? 'Cross' : 'Isolated',
      status: account.riskLevel
    };
  }, [account, positionSize, marginMode]);

  if (!riskData) return <div>Loading risk data...</div>;

  return (
    <Tooltip content={`Margin: ${riskData.marginMode}`}>
      <LTVRiskTooltipWidget
        ltv={riskData.ltv}
        status={riskData.status}
        symbol={symbol}
        liquidationPrice={riskData.liqPrice}
        onMarginChange={(mode) => console.log(mode)}
        interactive={true}
      />
    </Tooltip>
  );
};

export default AdvancedLTV;

