import React, { useState } from 'react';
import { MarginModeSettingsWidget } from '@orderly.network/ui-order-entry';
import { useMarginModes, useAccountInfo } from '@orderly.network/ui';

export function StandardSettings() {
  const { data: account } = useAccountInfo();
  const { data: modes, updateMode } = useMarginModes();
