      <h2>Margin Configuration</h2>
      <select
        value={selectedSymbol}
        onChange={(e) => setSelectedSymbol(e.target.value)}
      >
        <option value="BTC-PERP">BTC-PERP</option>
        <option value="ETH-PERP">ETH-PERP</option>
      </select>

      <MarginModeSettingsWidget
        symbol={selectedSymbol}
        currentMode={modes?.[selectedSymbol] || 'CROSS'}
        onModeChange={handleModeChange}
        accountInfo={account}
      />

      <div className="status">
        {modes?.[selectedSymbol] ? 'Updated' : 'Pending'}
      </div>
    </div>
  );
}

import React, { useEffect, useState } from 'react';
import { MarginModeSettingsWidget } from '@orderly.network/ui-order-entry';
import { useMarginModes, useAccountInfo, useSymbolLeverageMap } from '@orderly.network/ui';

export function AdvancedSettings() {
  const { data: account, isLoading: accLoading } = useAccountInfo();
  const { data: modes, updateMode, error: modeError } = useMarginModes();
  const { data: leverageMap } = useSymbolLeverageMap();
  const [symbol, setSymbol] = useState('BTC-PERP');
  const [mode, setMode] = useState('CROSS');
  const [isSaving, setIsSaving] = useState(false);

  useEffect(() => {
    if (modes && modes[symbol]) setMode(modes[symbol]);
  }, [modes, symbol]);

  const handleSave = async () => {
    setIsSaving(true);
    try {
      await updateMode({ symbol, mode });
    } catch (err) {
      console.error('Failed to update mode', err);
    } finally {
      setIsSaving(false);
    }
  };

  const maxLeverage = leverageMap?.[symbol]?.maxLeverage || 1;
  const isIsolated = mode === 'ISOLATED';

  return (
    <div className="advanced-margin-config">
      <header>
        <h3>Margin Mode & Leverage</h3>
        {modeError && <span className="error">{modeError.message}</span>}
      </header>

      <MarginModeSettingsWidget
        symbol={symbol}
        mode={mode}
        onModeChange={setMode}
        leverage={maxLeverage}
        disabled={isSaving || accLoading}
      />

      <div className="constraints">
        <p>Max Leverage: {maxLeverage}x</p>
        <p>Mode: {isIsolated ? 'Isolated' : 'Cross'}</p>
      </div>

      <button 
        onClick={handleSave}
        disabled={isSaving}
        className="primary-btn"
      >
        {isSaving ? 'Saving...' : 'Apply Settings'}
      </button>
    </div>
  );
}

