import React, { useMemo } from 'react';
import { MarginModeSwitchWidget } from '@orderly.network/ui-order-entry';
import { useMarginModeBySymbol, useOrderEntry, useSymbolLeverageMap } from '@orderly.network/ui';

export function AdvancedSwitch() {
  const { symbol, updateOrder } = useOrderEntry();
  const { data: modeData } = useMarginModeBySymbol({ symbol });
  const { data: leverageMap } = useSymbolLeverageMap();

  const maxLeverage = useMemo(() => {
    return leverageMap?.[symbol]?.maxLeverage || 125;
  }, [leverageMap, symbol]);

  const handleModeChange = (mode) => {
    updateOrder({ marginMode: mode });
    // Reset leverage if switching to isolated to safe default
    if (mode === 'ISOLATED') {
      updateOrder({ leverage: 10 });
    }
  };

  const riskWarning = modeData?.mode === 'ISOLATED' 
    ? 'Liquidation risk is higher in Isolated mode.' 
    : '';

  return (
    <div className="order-entry-controls">
      <div className="mode-selector">
        <MarginModeSwitchWidget
          symbol={symbol}
          currentMode={modeData?.mode}
          onModeChange={handleModeChange}
          maxLeverage={maxLeverage}
        />
      </div>

      {riskWarning && (
        <div className="risk-alert">
          <span className="icon">⚠️</span>
          <p>{riskWarning}</p>
        </div>
      )}

      <div className="leverage-display">
        Current Leverage: {modeData?.leverage || 1}x
      </div>
    </div>
  );
}

