import React from 'react';
import { InputPrefix, Input, Button } from '@orderly.network/ui';
import { useOrderEntry } from '@orderly.network/hooks';

export function OrderFormPrefix() {
  const { submitOrder, isPending } = useOrderEntry();
  const [price, setPrice] = React.useState('');
  const [error, setError] = React.useState('');

  const handlePriceChange = (val) => {
    if (parseFloat(val) <= 0) setError('Price must be positive');
    else setError('');
    setPrice(val);
  };

  const handleSubmit = () => {
    if (!error && price) submitOrder({ price });
  };

  return (
    <div className='p-4 border rounded'>
      <InputPrefix prefix='USD'>
        <Input
          value={price}
          onChange={(e) => handlePriceChange(e.target.value)}
          placeholder='0.00'
          className={error ? 'border-red-500' : ''}
        />
      </InputPrefix>
      {error && <span className='text-red-500 text-sm'>{error}</span>}
      <Button
        onClick={handleSubmit}
        disabled={isPending || !!error}
        className='mt-2 w-full'
      >
        {isPending ? 'Submitting...' : 'Place Order'}
      </Button>
    </div>
  );
}

