import React from 'react';
import { InputSuffix, Input, Button } from '@orderly.network/ui';
import { useMaxQty, useOrderEntry } from '@orderly.network/hooks';

export function MaxQtySuffix() {
  const { symbol } = useOrderEntry();
  const { maxQty } = useMaxQty(symbol);
  const [qty, setQty] = React.useState('');
  const [error, setError] = React.useState('');

  const handleChange = (val) => {
    const num = parseFloat(val);
    if (maxQty && num > maxQty) {
      setError(`Max: ${maxQty}`);
    } else {
      setError('');
    }
    setQty(val);
  };

  return (
    <div className='relative'>
      <InputSuffix suffix='BTC'>
        <Input
          value={qty}
          onChange={(e) => handleChange(e.target.value)}
          placeholder='0.00'
          className={error ? 'border-red-500' : ''}
        />
      </InputSuffix>
      {error && (
        <span className='absolute -bottom-5 right-0 text-xs text-red-500'>
          {error}
        </span>
      )}
      <Button
        onClick={() => setQty(maxQty || '0')}
        className='mt-2 text-xs'
      >
        Max
      </Button>
    </div>
  );
