import React, { useState, useMemo } from 'react';
import { TextField } from '@orderly.network/ui';

interface ValidatedTextFieldProps {
  label: string;
  value: string;
  onChange: (v: string) => void;
  min?: number;
  max?: number;
}

export function ValidatedTextField({
  label,
  value,
  onChange,
  min = 0,
  max = 1000000
}: ValidatedTextFieldProps) {
  const [error, setError] = useState<string | null>(null);

  const validate = (val: string) => {
    const num = parseFloat(val);
    if (isNaN(num)) return 'Invalid number';
    if (num < min) return `Min value is ${min}`;
    if (num > max) return `Max value is ${max}`;
    return null;
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newVal = e.target.value;
    const err = validate(newVal);
    setError(err);
    if (!err) onChange(newVal);
  };

  const formattedValue = useMemo(() => {
    if (!value) return '';
    return parseFloat(value).toFixed(2);
  }, [value]);

  return (
    <div className="space-y-2">
      <div className="flex justify-between">
        <label className="text-sm font-semibold">{label}</label>
        <span className="text-xs text-gray-500">{min} - {max}</span>
      </div>
      <TextField
        value={formattedValue}
        onChange={handleChange}
        error={error}
        className="w-full border rounded p-2"
      />
      {error && (
        <p className="text-xs text-red-600 animate-pulse">{error}</p>
      )}
    </div>
  );
}

import React, { useEffect, useState } from 'react';
import { TextField } from '@orderly.network/ui';
import { useOrderEntry } from '@orderly.network/ui';
import { useMaxQty } from '@orderly.network/ui';

interface TradingTextFieldProps {
  symbol: string;
  side: 'buy' | 'sell';
  label: string;
  type: 'price' | 'quantity';
}

export function TradingTextField({
  symbol,
  side,
  label,
  type
}: TradingTextFieldProps) {
  const { orderEntry } = useOrderEntry();
  const { maxQty } = useMaxQty(symbol);
  const [value, setValue] = useState<string>('');
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (type === 'quantity' && maxQty) {
      setValue(maxQty.toString());
    }
  }, [maxQty, type]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newVal = e.target.value;
    setValue(newVal);
    setError(null);

    if (type === 'quantity') {
      const num = parseFloat(newVal);
      if (maxQty && num > maxQty) {
        setError(`Exceeds max qty: ${maxQty}`);
      }
    }
  };

  const handleSubmit = () => {
    if (error || !value) return;
    orderEntry.submit({
      symbol,
      side,
      [type]: parseFloat(value)
    });
  };

  return (
    <div className="p-4 border rounded-lg bg-white shadow-sm">
      <div className="flex items-center justify-between mb-2">
        <span className="font-bold text-gray-700">{label}</span>
        <span className="text-xs text-gray-400">{symbol}</span>
      </div>
      <TextField
        value={value}
        onChange={handleChange}
        error={error}
        placeholder="0.00"
        className="w-full mb-2"
      />
      <button
        onClick={handleSubmit}
        disabled={!!error || !value}
        className="w-full py-2 bg-blue-600 text-white rounded disabled:opacity-50"
      >
        Place Order
      </button>
      {maxQty && (
        <p className="text-xs text-gray-500 mt-1">
          Max Available: {maxQty}
        </p>
      )}
    </div>
  );
}

