import React, { useState } from 'react';
import { useAccountInfo, useApiStatusActions } from '@orderly.network/ui';

export function WalletManager() {
  const { account, isConnected, connect, disconnect } = useAccountInfo();
  const { status, checkStatus } = useApiStatusActions();
  const [loading, setLoading] = useState(false);

  const handleConnect = async () => {
    setLoading(true);
    try {
      await connect();
      await checkStatus();
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleDisconnect = async () => {
    setLoading(true);
    try {
      await disconnect();
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex flex-col gap-4 p-4 border rounded">
      <div className="flex justify-between items-center">
        <h3 className="font-bold">Wallet Status</h3>
        <span className={`text-xs px-2 py-1 rounded ${
          status === 'active' ? 'bg-green-100 text-green-800' : 'bg-gray-100'
        }`}>
          {status}
        </span>
      </div>

      {isConnected ? (
        <div className="space-y-2">
          <p className="text-sm">Address: {account?.address}</p>
          <button
            onClick={handleDisconnect}
            disabled={loading}
            className="px-4 py-2 bg-red-500 text-white rounded disabled:opacity-50"
          >
            {loading ? '...' : 'Disconnect'}
          </button>
        </div>
      ) : (
        <button
          onClick={handleConnect}
          disabled={loading}
          className="px-4 py-2 bg-blue-600 text-white rounded disabled:opacity-50"
        >
          {loading ? 'Connecting...' : 'Connect Wallet'}
        </button>
      )}
    </div>
  );
}

import React, { createContext, useContext, useEffect } from 'react';
import { useAccountInfo, useApiKeyManager } from '@orderly.network/ui';
import { useApiStatusActions } from '@orderly.network/ui';

interface ProviderContextType {
  isConnected: boolean;
  apiKey: string | null;
  refreshKey: () => Promise<void>;
}

const ProviderContext = createContext<ProviderContextType | null>(null);

export function OrderlyProvider({ children }: { children: React.ReactNode }) {
  const { account, isConnected, connect, disconnect } = useAccountInfo();
  const { apiKey, generateKey } = useApiKeyManager();
  const { status, checkStatus } = useApiStatusActions();
  const [error, setError] = useState<string | null>(null);

  const refreshKey = async () => {
    try {
      await generateKey();
      await checkStatus();
      setError(null);
    } catch (e) {
      setError('Failed to refresh API Key');
    }
  };

  useEffect(() => {
    if (isConnected && !apiKey) {
      refreshKey();
    }
  }, [isConnected]);

  const value = {
    isConnected,
    apiKey,
    refreshKey
  };

  return (
    <ProviderContext.Provider value={value}>
      <div className="relative">
        {error && (
          <div className="absolute top-0 right-0 bg-red-100 text-red-800 p-2 rounded">
            {error}
          </div>
        )}
        {children}
      </div>
    </ProviderContext.Provider>
  );
}

export function useOrderlyProvider() {
  const context = useContext(ProviderContext);
  if (!context) throw new Error('Must use within OrderlyProvider');
  return context;
}

export function ProviderStatus() {
  const { isConnected, apiKey } = useOrderlyProvider();
  const { account } = useAccountInfo();

  return (
    <div className="p-4 bg-gray-50 border rounded">
      <div className="flex justify-between mb-2">
        <span>Connection:</span>
        <span className={isConnected ? 'text-green-600' : 'text-red-600'}>
          {isConnected ? 'Active' : 'Inactive'}
        </span>
      </div>
      <div className="flex justify-between">
        <span>API Key:</span>
        <span className="text-xs font-mono">
          {apiKey ? `${apiKey.slice(0, 8)}...` : 'None'}
        </span>
      </div>
      {account && (
        <div className="mt-2 text-xs text-gray-500">
          {account.address}
        </div>
      )}
    </div>
  );
}

