import React, { useState } from 'react';
import { ExtensionSlot } from '@orderly.network/ui';
import { useAccountInfo, useOrderEntry } from '@orderly.network/hooks';

/**
 * Advanced ExtensionSlot Example
 * Allows quick order placement directly from the slot.
 */
export default function TradingExtension() {
  const { data: account } = useAccountInfo();
  const { submitOrder, isSubmitting } = useOrderEntry();
  const [side, setSide] = useState('BUY');
  const [amount, setAmount] = useState('');

  const handleQuickTrade = async (e) => {
    e.preventDefault();
    if (!amount || !account) return;

    try {
      await submitOrder({
        symbol: 'BTC/USDT',
        side: side,
        type: 'MARKET',
        quantity: parseFloat(amount)
      });
      setAmount('');
    } catch (err) {
      console.error('Order failed', err);
    }
  };

  const inputStyle = {
    width: '100%',
    padding: '8px',
    marginBottom: '8px',
    borderRadius: '4px',
    border: '1px solid #d1d5db'
  };

  const buttonStyle = {
    width: '100%',
    padding: '10px',
    borderRadius: '4px',
    border: 'none',
    fontWeight: 'bold',
    cursor: 'pointer',
    opacity: isSubmitting ? 0.7 : 1
  };

  return (
    <ExtensionSlot>
      <div style={{
        padding: '16px',
        backgroundColor: '#1f2937',
        borderRadius: '8px',
        color: 'white'
      }}>
        <div style={{ display: 'flex', gap: '8px', marginBottom: '12px' }}>
          <button
            onClick={() => setSide('BUY')}
            style={{
              ...buttonStyle,
              background: side === 'BUY' ? '#10b981' : '#374151',
              color: 'white'
            }}
          >
            BUY
          </button>
          <button
            onClick={() => setSide('SELL')}
            style={{
              ...buttonStyle,
              background: side === 'SELL' ? '#ef4444' : '#374151',
              color: 'white'
            }}
          >
            SELL
          </button>
        </div>
        <form onSubmit={handleQuickTrade}>
          <input
            type="number"
            placeholder="Amount (USDT)"
            value={amount}
            onChange={(e) => setAmount(e.target.value)}
            style={inputStyle}
          />
          <button
            type="submit"
            disabled={isSubmitting}
            style={{
              ...buttonStyle,
              background: side === 'BUY' ? '#10b981' : '#ef4444',
              color: 'white'
            }}
          >
            {isSubmitting ? 'Processing...' : 'Execute'}
          </button>
        </form>
        <div style={{ marginTop: '12px', fontSize: '12px', color: '#9ca3af' }}>
          Available: {account?.balances?.[0]?.amount || 0} USDT
        </div>
      </div>
    </ExtensionSlot>
  );
}

