    subscribe('order_update', (payload) => {
      setLiveOrders(prev => {
        const idx = prev.findIndex(o => o.id === payload.id);
        if (idx >= 0) {
          const newOrders = [...prev];
          newOrders[idx] = { ...newOrders[idx], ...payload };
          return newOrders;
        }
        return [payload, ...prev];
      });
    });

    return () => unsubscribe('order_update');
  }, [subscribe, unsubscribe]);

  const handleCancel = async (id) => {
    console.log(`Cancelling order ${id}`);
    // Call cancel API here
  };

  const columns = [
    { key: 'symbol', label: 'Symbol' },
    { key: 'side', label: 'Side', render: v => <span className={v === 'buy' ? 'text-green-600' : 'text-red-600'}>{v}</span> },
    { key: 'price', label: 'Price', align: 'right' },
    { key: 'status', label: 'Status' },
    {
      key: 'actions',
      label: 'Actions',
      render: (_, row) => (
        <button 
          onClick={() => handleCancel(row.id)}
          className="text-xs bg-gray-200 px-2 py-1 rounded hover:bg-gray-300"
        >
          Cancel
        </button>
      )
    }
  ];

  return (
    <div className="p-4 border-t-4 border-blue-500 bg-gray-50 min-h-screen">
      <h1 className="text-2xl font-bold mb-6">Live Order Book</h1>
      <DataTable
        data={liveOrders}
        columns={columns}
        rowKey="id"
        sortable={true}
        onSort={(col) => console.log('Sorted by', col)}
      />
      <div className="mt-4 text-xs text-gray-400">
        WebSocket Status: Connected
      </div>
    </div>
  );
}

