import React, { useState } from 'react';
import { AuthGuardEmpty } from '@orderly.network/ui-connector';
import { useAccountInfo, useApiKeyManager } from '@orderly.network/react';

export default function SecureGateway() {
  const { isConnected, error } = useAccountInfo();
  const { hasApiKey, checkApiKey } = useApiKeyManager();
  const [showError, setShowError] = useState(false);

  const handleConnect = async () => {
    try {
      await checkApiKey();
      setShowError(false);
    } catch (err) {
      setShowError(true);
    }
  };

  if (isConnected && hasApiKey) {
    return <div>Secure Access Granted</div>;
  }

  return (
    <div className="secure-container">
      {showError && <div className="error-msg">API Key Missing</div>}
      <AuthGuardEmpty
        onConnect={handleConnect}
        variant="api-required"
        theme="dark"
      />
      <footer>
        <small>Protected by Orderly Network</small>
      </footer>
    </div>
  );
}

