import React, { useState, useEffect } from 'react';
import { LeverageInput } from '@orderly.network/ui-leverage';
import { useSymbolLeverageMap } from '@orderly.network/hooks';

export default function ValidatedLeverageInput({ symbol }) {
  const [value, setValue] = useState(10);
  const { data: leverageMap } = useSymbolLeverageMap();
  const limits = leverageMap?.[symbol] || { min: 1, max: 125 };

  useEffect(() => {
    if (value < limits.min) setValue(limits.min);
    if (value > limits.max) setValue(limits.max);
  }, [limits, value]);

  return (
    <div className="flex flex-col gap-2">
      <label>Max: {limits.max}x</label>
      <LeverageInput
        value={value}
        onChange={setValue}
        min={limits.min}
        max={limits.max}
      />
      <span className="text-sm text-gray-500">
        {value}x Selected
      </span>
    </div>
  );
}

import React, { useState, useCallback } from 'react';
import { LeverageInput } from '@orderly.network/ui-leverage';
import { useSymbolLeverageMap, useMarginModeBySymbol } from '@orderly.network/hooks';

export default function AdvancedLeverageInput({ symbol, onLeverageChange }) {
  const [inputVal, setInputVal] = useState('');
  const [error, setError] = useState(null);
  const { data: leverageMap } = useSymbolLeverageMap();
  const { data: marginMode } = useMarginModeBySymbol(symbol);

  const limits = leverageMap?.[symbol] || { min: 1, max: 125 };

  const handleChange = useCallback((val) => {
    if (val < limits.min) {
      setError(`Min leverage is ${limits.min}x`);
      return;
    }
    if (val > limits.max) {
      setError(`Max leverage is ${limits.max}x`);
      return;
    }
    setError(null);
    setInputVal(val);
    onLeverageChange(val);
  }, [limits, onLeverageChange]);

  return (
    <div className="relative">
      <LeverageInput
        value={inputVal}
        onChange={handleChange}
        disabled={!marginMode}
      />
      {error && (
        <div className="absolute top-full text-red-500 text-xs">
          {error}
        </div>
      )}
      <div className="text-xs text-gray-400 mt-1">
        Mode: {marginMode || 'Loading'}
      </div>
    </div>
  );
}

