import React, { useMemo } from 'react';
import { LeverageSelector } from '@orderly.network/ui-leverage';
import { useSymbolLeverageMap } from '@orderly.network/hooks';

export default function DynamicSelector({ symbol }) {
  const { data: leverageMap } = useSymbolLeverageMap();

  const options = useMemo(() => {
    if (!leverageMap?.[symbol]) return [1, 5, 10];
    const max = leverageMap[symbol].max;
    return [1, 5, 10, 20, 50, 100].filter(x => x <= max);
  }, [leverageMap, symbol]);

  return (
    <div className="flex gap-2 items-center">
      <span>Leverage:</span>
      <LeverageSelector
        options={options}
        onSelect={(val) => console.log('Selected', val)}
        className="w-32"
      />
    </div>
  );
}

import React, { useState } from 'react';
import { LeverageSelector } from '@orderly.network/ui-leverage';
import { useSymbolLeverageMap, useAccountInfo } from '@orderly.network/hooks';

export default function SmartSelector({ symbol, positionSize }) {
  const [selected, setSelected] = useState(10);
  const { data: leverageMap } = useSymbolLeverageMap();
  const { data: account } = useAccountInfo();

  const maxLeverage = leverageMap?.[symbol]?.max || 125;
  const availableMargin = account?.marginAvailable || 0;
  const requiredMargin = positionSize / selected;
  const isSufficient = availableMargin >= requiredMargin;

  return (
    <div className="border p-4 rounded">
      <LeverageSelector
        value={selected}
        onChange={(val) => setSelected(val)}
        max={maxLeverage}
        options={[1, 5, 10, 20, 50, 100]}
      />
      <div className="mt-2 text-sm">
        <p>Margin Req: ${requiredMargin.toFixed(2)}</p>
        <p className={isSufficient ? 'text-green-600' : 'text-red-600'}>
          {isSufficient ? 'Sufficient' : 'Insufficient Funds'}
        </p>
      </div>
    </div>
  );
}

