import { Button, Input, Alert } from '@orderly.network/ui';
import { useOrderEntry, useApiKeyManager, useAccountInfo } from '@orderly.network/hooks';
import React from 'react';

export const AdditionalConfigButton = () => {
  const { leverage, setLeverage } = useOrderEntry();
  const { apiKey } = useApiKeyManager();
  const { account } = useAccountInfo();
  const [isOpen, setIsOpen] = React.useState(false);
  const [error, setError] = React.useState('');

  const handleLeverageChange = (val) => {
    if (val > account?.maxLeverage) {
      setError('Exceeds account limit');
      return;
    }
    setError('');
    setLeverage(val);
  };

  return (
    <div className="flex flex-col gap-2">
      <Button onClick={() => setIsOpen(!isOpen)}>
        {isOpen ? 'Collapse' : 'Configure Order'}
      </Button>
      {isOpen && (
        <div className="p-4 border rounded bg-white shadow">
          {error && <Alert variant="destructive">{error}</Alert>}
          <div className="mb-2">
            <label>Leverage</label>
            <Input
              type="number"
              value={leverage}
              onChange={(e) => handleLeverageChange(Number(e.target.value))}
            />
          </div>
          <div className="text-xs">
            API Key: {apiKey ? 'Active' : 'Not Set'}
          </div>
        </div>
      )}
    </div>
  );
};

