  const { closePosition } = usePositionClose();
  const [selectedSymbol, setSelectedSymbol] = useState('BTC-PERP');

  const position = positions?.find(p => p.symbol === selectedSymbol);
  if (!position) return <div>Loading...</div>;

  const handleModify = () => {
    submitOrder({ symbol: selectedSymbol, side: 'CLOSE', qty: position.size });
  };

  const handleClose = () => {
    closePosition({ symbol: selectedSymbol });
  };

  return (
    <div className="p-4 border rounded">
      <AdvancedTPSLResult 
        data={{
          ...position,
          pnl: position.unrealizedPnl
        }} 
        onModify={handleModify}
        onClose={handleClose}
      />
    </div>
  );
}

