export default function TieredFeeDisplay() {
  const { symbol, side, price, quantity, isSubmitting } = useOrderEntry();
  const { accountInfo, isLoading } = useAccountInfo();

  const feeConfig = useMemo(() => {
    if (!accountInfo) return null;
    return {
      vipLevel: accountInfo.vipLevel,
      makerRate: accountInfo.makerFeeRate,
      takerRate: accountInfo.takerFeeRate,
    };
  }, [accountInfo]);

  if (isLoading) {
    return <div className="animate-pulse h-12 bg-gray-200 rounded" />;
  }

  if (!symbol) {
    return <div className="text-sm text-gray-400">Select a pair</div>;
  }

  return (
    <div className="fee-widget bg-gray-50 p-4 rounded-lg">
      <div className="flex justify-between items-center mb-2">
        <span className="text-xs font-bold text-gray-600">
          VIP {feeConfig?.vipLevel || 0}
        </span>
        <span className="text-xs text-blue-600">
          {feeConfig?.makerRate}% Maker
        </span>
      </div>

      <EffectiveFeeUI
        symbol={symbol}
        side={side}
        price={price}
        quantity={quantity}
        showBreakdown={true}
        disabled={isSubmitting}
      />

      {isSubmitting && (
        <div className="text-xs text-orange-500 mt-1">
          Calculating final fees...
        </div>
      )}
    </div>
  );
