import React, { useState, useEffect } from 'react';
import { EffectiveFeeUI } from '@orderly.network/ui-order-entry';
import { useOrderEntry, useAccountInfo, usePortfolio } from '@orderly.network/hooks';

export default function AdvancedFeeManager() {
  const { symbol, side, price, quantity, error } = useOrderEntry();
  const { accountInfo } = useAccountInfo();
  const { portfolio } = usePortfolio();
  const [feeError, setFeeError] = useState<string | null>(null);

  useEffect(() => {
    if (error) setFeeError(error.message);
    else setFeeError(null);
  }, [error]);

  const canTrade = useMemo(() => {
    if (!portfolio || !accountInfo) return false;
    const balance = portfolio.balances.find(b => b.asset === symbol);
    return balance && Number(balance.available) > 0;
  }, [portfolio, accountInfo, symbol]);

  const handleFeeClick = (info: any) => {
    console.log('Fee details clicked:', info);
    // Trigger analytics or tooltip expansion
  };

  if (!symbol) return null;

  return (
    <div className="relative w-full max-w-md mx-auto">
      <div className="bg-white border rounded-xl shadow-lg overflow-hidden">
        <div className="p-4 border-b flex justify-between">
          <h2 className="font-bold text-gray-800">Fee Estimate</h2>
          {feeError && (
            <span className="text-red-500 text-xs">Calculation Error</span>
          )}
        </div>

        <div className="p-4">
          <EffectiveFeeUI
            symbol={symbol}
            side={side}
            price={price}
            quantity={quantity}
            accountTier={accountInfo?.vipLevel}
            onFeeDetails={handleFeeClick}
            interactive={true}
          />

          <div className="mt-4 space-y-2">
            <div className="flex justify-between text-sm">
              <span className="text-gray-500">Available Balance:</span>
              <span className={canTrade ? 'text-green-600' : 'text-red-500'}>
                {portfolio?.balances.find(b => b.asset === symbol)?.available || '0'}
              </span>
            </div>
            <div className="flex justify-between text-sm">
              <span className="text-gray-500">Discount Applied:</span>
              <span className="text-blue-600">{accountInfo?.discountRate || 0}%</span>
            </div>
          </div>
        </div>

        <div className="bg-gray-50 p-3 text-xs text-gray-400 border-t">
          Fees are estimates and subject to market volatility.
        </div>
      </div>
    </div>
  );
}

