import React, { useMemo } from 'react';
import { usePortfolio, useOrderEntry, useMarginModeBySymbol } from '@orderly.network/ui-order-entry';

export default function PnlInputProviderAdvanced() {
  const { portfolio } = usePortfolio();
  const { formState } = useOrderEntry();
  const { marginMode } = useMarginModeBySymbol(formState.symbol);

  const estimatedPnl = useMemo(() => {
    if (!formState.price || !formState.quantity) return 0;
    // Simplified estimation logic
    const entryPrice = parseFloat(formState.price);
    const currentPrice = portfolio?.markPrice || entryPrice;
    const diff = currentPrice - entryPrice;
    return (formState.side === 'buy' ? diff : -diff) * parseFloat(formState.quantity);
  }, [formState, portfolio]);

  const riskLevel = Math.abs(estimatedPnl) > 1000 ? 'High' : 'Low';

  return (
    <div className="p-4 border rounded bg-white">
      <div className="flex justify-between mb-4">
        <span className="text-sm">Margin: {marginMode}</span>
        <span className={`text-sm font-bold ${riskLevel === 'High' ? 'text-orange-500' : 'text-gray-500'}`}>
          Risk: {riskLevel}
        </span>
      </div>
      <div className="space-y-3">
        <div className="flex justify-between border-b pb-2">
          <span className="text-gray-600">Current PnL</span>
          <span className="font-bold">{portfolio?.unrealizedPnl?.toFixed(2)}</span>
        </div>
        <div className="flex justify-between border-b pb-2">
          <span className="text-gray-600">Est. Order PnL</span>
          <span className={`font-bold ${estimatedPnl >= 0 ? 'text-green-600' : 'text-red-600'}`}>
            {estimatedPnl.toFixed(2)}
          </span>
        </div>
        <div className="flex justify-between">
          <span className="text-gray-600">Projected Total</span>
          <span className="font-bold">
            {(portfolio?.unrealizedPnl + estimatedPnl).toFixed(2)}
          </span>
        </div>
      </div>
      {riskLevel === 'High' && (
        <p className="mt-2 text-xs text-orange-600 bg-orange-50 p-2 rounded">
          Warning: High exposure detected on this order.
        </p>
      )}
    </div>
  );
}

