import React, { useEffect, useState } from 'react';
import { ReduceOnlySwitch } from '@orderly.network/ui-order-entry';
import { useOrderEntry, useAccountInfo } from '@orderly.network/ui-order-entry';

export default function AdvancedSwitch() {
  const { orderState, updateOrder } = useOrderEntry();
  const { positions } = useAccountInfo();
  const [reduceOnly, setReduceOnly] = useState(false);
  const [hasPosition, setHasPosition] = useState(false);

  useEffect(() => {
    const pos = positions.find(p => p.symbol === orderState.symbol);
    setHasPosition(!!pos && pos.size !== 0);
  }, [positions, orderState.symbol]);

  const handleChange = (val) => {
    if (val && !hasPosition) {
      alert('No open position to reduce');
      return;
    }
    setReduceOnly(val);
    updateOrder({ reduceOnly: val });
  };

  return (
    <div className="relative">
      <ReduceOnlySwitch
        checked={reduceOnly}
        onChange={handleChange}
        disabled={!hasPosition && reduceOnly}
      />
      {!hasPosition && reduceOnly && (
        <span className="text-xs text-red-500 ml-2">
          No position
        </span>
      )}
    </div>
  );
}

