import React, { useState, useEffect } from 'react';
import { OrderEntry, ReduceOnlySwitch } from '@orderly.network/ui-order-entry';
import { useOrderEntry, useAccountInfo, useMaxQty, useMarginModes } from '@orderly.network/ui-order-entry';

export default function AdvancedOrderEntry() {
  const { submitOrder, orderState, updateOrder } = useOrderEntry();
  const { account } = useAccountInfo();
  const { maxQty } = useMaxQty(orderState.symbol);
  const { marginMode } = useMarginModes();
  const [type, setType] = useState('LIMIT');
  const [leverage, setLeverage] = useState(1);
  const [reduceOnly, setReduceOnly] = useState(false);

  useEffect(() => {
    updateOrder({ symbol: 'BTC-PERP' });
  }, []);

  const handlePlace = async () => {
    if (!maxQty) return;
    const qty = Math.min(orderState.qty, maxQty);
    await submitOrder({ ...orderState, qty, type, reduceOnly, leverage });
  };

  const canSubmit = orderState.price > 0 && orderState.qty > 0;

  return (
    <div className="p-4 border rounded bg-gray-50 w-96">
      <div className="flex justify-between mb-4">
        <span className="font-bold">BTC-PERP</span>
        <span className="text-xs">{marginMode} Mode</span>
      </div>

      <div className="grid grid-cols-2 gap-2 mb-4">
        <button
          onClick={() => setType('LIMIT')}
          className={`p-2 ${type === 'LIMIT' ? 'bg-blue-500 text-white' : 'bg-gray-200'}`}
        >
          Limit
        </button>
        <button
          onClick={() => setType('MARKET')}
          className={`p-2 ${type === 'MARKET' ? 'bg-blue-500 text-white' : 'bg-gray-200'}`}
        >
          Market
        </button>
      </div>

      <div className="mb-4">
        <label className="text-xs">Leverage ({leverage}x)</label>
        <input
          type="range" min="1" max="20"
          value={leverage}
          onChange={(e) => setLeverage(Number(e.target.value))}
          className="w-full"
        />
      </div>

      <div className="mb-2">
        <label className="text-xs">Price</label>
        <input
          type="number"
          value={orderState.price}
          onChange={(e) => updateOrder({ price: e.target.value })}
          className="w-full border p-2"
        />
      </div>

      <div className="mb-2">
        <label className="text-xs">Qty (Max: {maxQty})</label>
        <input
          type="number"
          value={orderState.qty}
          onChange={(e) => updateOrder({ qty: e.target.value })}
          className="w-full border p-2"
        />
      </div>

      <div className="flex justify-between items-center mb-4">
        <span className="text-xs">Balance: {account?.balance}</span>
        <ReduceOnlySwitch
          checked={reduceOnly}
          onChange={setReduceOnly}
        />
      </div>

      <button
        disabled={!canSubmit}
        onClick={handlePlace}
        className={`w-full p-3 rounded font-bold ${canSubmit ? 'bg-green-600 text-white' : 'bg-gray-300'}`}
      >
        Buy BTC
      </button>
    </div>
  );
}

