import React, { useEffect, useState } from 'react';
import { MobileOrderListWidget } from '@orderly.network/ui-orders';
import { useOrderEntity, usePortfolio, usePositionClose, useWSObserver } from '@orderly.network/ui';

export default function AdvancedOrderList() {
  const { account } = usePortfolio();
  const { orders, refreshOrders } = useOrderEntity({ status: 'all' });
  const { closePosition } = usePositionClose();
  const { subscribe } = useWSObserver();
  const [activeTab, setActiveTab] = useState('open');

  useEffect(() => {
    subscribe('orders', refreshOrders);
    return () => unsubscribe('orders');
  }, [subscribe, refreshOrders]);

  const handleCancel = (orderId) => {
    refreshOrders();
  };

  const handleClose = (positionId) => {
    closePosition(positionId);
    refreshOrders();
  };

  if (!account) return <div>Authentication Required</div>;

  return (
    <div className="advanced-order-panel">
      <div className="tabs">
        <button onClick={() => setActiveTab('open')}>Open</button>
        <button onClick={() => setActiveTab('history')}>History</button>
      </div>
      <MobileOrderListWidget
        orders={orders}
        account={account}
        filter={activeTab}
        onOrderCancel={handleCancel}
        onPositionClose={handleClose}
        showPnL={true}
      />
    </div>
  );
}

