import React, { useState, useCallback } from 'react';
import { MobilePositionHistoryWidget } from '@orderly.network/ui-positions';
import { usePortfolio, usePositionClose, useAccountInfo } from '@orderly.network/hooks';

/**
 * Advanced implementation with interactive actions.
 * Allows closing positions directly from the history list.
 */
export default function InteractiveHistoryView() {
  const { data: portfolio } = usePortfolio();
  const { data: account } = useAccountInfo();
  const { closePosition, isClosing } = usePositionClose();
  const [selectedPos, setSelectedPos] = useState(null);

  const handleAction = useCallback(async (positionId) => {
    if (!account?.apiKey) return;
    try {
      await closePosition({
        positionId,
        accountId: account.id,
      });
      setSelectedPos(null);
    } catch (err) {
      console.error('Close failed', err);
    }
  }, [closePosition, account]);

  return (
    <div className="flex flex-col h-screen bg-slate-50">
      {/* Top Bar */}
      <div className="p-4 bg-white border-b">
        <h1 className="text-2xl font-bold text-slate-900">
          Trade History
        </h1>
      </div>

      {/* Main Content */}
      <div className="flex-1 overflow-y-auto p-4">
        <MobilePositionHistoryWidget
          data={portfolio?.positions}
          onPositionSelect={setSelectedPos}
          actionButton={selectedPos ? (
            <button
              onClick={() => handleAction(selectedPos.id)}
              disabled={isClosing}
              className="w-full mt-2 bg-red-500 text-white py-2 rounded"
            >
              {isClosing ? 'Closing...' : 'Close Position'}
            </button>
          ) : null}
          className="rounded-xl shadow-lg"
        />
      </div>

      {/* Status Toast */}
      {isClosing && (
        <div className="fixed bottom-4 left-4 right-4 bg-slate-800 text-white p-3 rounded shadow-lg text-center">
          Processing close request...
        </div>
      )}
    </div>
  );
}

