import React, { useState, useEffect } from 'react';
import { NumeralWithCtx } from '@orderly.network/ui-positions';
import { useWSObserver, usePortfolio } from '@orderly.network/hooks';

/**
 * Advanced implementation with WebSocket live updates.
 * Formats numbers with high precision for trading data.
 */
export default function LiveTickerDisplay() {
  const [livePrice, setLivePrice] = useState(0);
  const { data: portfolio } = usePortfolio();

  // Subscribe to price updates via WebSocket
  const { data: wsData } = useWSObserver({
    channel: 'ticker',
    symbol: 'BTC-USDT',
  });

  useEffect(() => {
    if (wsData?.price) {
      setLivePrice(parseFloat(wsData.price));
    }
  }, [wsData]);

  const pnl = portfolio?.pnl || 0;

  return (
    <div className="border rounded-lg p-6 bg-slate-900 text-white">
      <div className="flex justify-between items-start mb-6">
        <div>
          <h4 className="text-slate-400 text-sm">BTC/USDT Price</h4>
          <NumeralWithCtx
            value={livePrice}
            currency="USDT"
            precision={2}
            className="text-3xl font-mono text-yellow-400"
          />
        </div>
        <div className="text-right">
          <h4 className="text-slate-400 text-sm">Unrealized PnL</h4>
          <NumeralWithCtx
            value={pnl}
            currency="USDT"
            precision={4}
            className={`text-xl font-bold ${
              pnl >= 0 ? 'text-green-400' : 'text-red-400'
            }`}
          />
        </div>
      </div>

      {/* Flash effect on update */}
      <div className="h-1 w-full bg-slate-800 rounded overflow-hidden">
        <div 
          className="h-full bg-blue-500 transition-all duration-300"
          style={{ width: `${Math.min(livePrice / 1000, 100)}%` }}
        />
      </div>
    </div>
  );
}

