import React, { useState, useEffect } from 'react';
import { MobilePositions } from '@orderly.network/ui-positions';
import { usePortfolio } from '@orderly.network/react';

export default function AdvancedMobile() {
  const { data, refetch, isLoading } = usePortfolio();
  const [filter, setFilter] = useState('all');

  useEffect(() => {
    const interval = setInterval(refetch, 5000);
    return () => clearInterval(interval);
  }, [refetch]);

  const filteredData = data?.positions?.filter(p => {
    if (filter === 'all') return true;
    return p.symbol.includes(filter);
  });

  if (isLoading) return <div className="p-4 text-center">Syncing...</div>;

  return (
    <div className="p-4 space-y-4">
      <div className="flex gap-2 overflow-x-auto">
        {['all', 'BTC', 'ETH'].map(f => (
          <button
            key={f}
            onClick={() => setFilter(f)}
            className={`px-3 py-1 rounded-full text-sm ${
              filter === f ? 'bg-blue-600 text-white' : 'bg-gray-200'
            }`}
          >
            {f}
          </button>
        ))}
      </div>
      <MobilePositions 
        positions={filteredData}
        emptyMessage="No open positions"
        className="space-y-2"
      />
    </div>
  );
}

