import React, { useEffect, useState } from 'react';
import { PositionsWidget } from '@orderly.network/ui-positions';
import { usePortfolio, usePositionClose, useWSObserver } from '@orderly.network/sdk';

export default function AdvancedWidget() {
  const { data: portfolio, refetch } = usePortfolio();
  const closeMutation = usePositionClose();
  const [wsData, setWsData] = useState(null);

  // Subscribe to position updates via WebSocket
  useWSObserver({
    topic: 'positions',
    onMessage: (msg) => {
      setWsData(msg);
      refetch(); // Trigger refetch on WS update
    }
  });

  const handleAction = async (pos, action) => {
    if (action === 'close') {
      await closeMutation.mutateAsync({ positionId: pos.id });
    }
  };

  return (
    <div className="flex flex-col h-full">
      <header className="p-3 bg-blue-600 text-white flex justify-between">
        <h2 className="font-bold">Active Positions</h2>
        <span className="text-xs">
          {wsData ? 'Live' : 'Static'}
        </span>
      </header>
      <div className="flex-1 overflow-auto">
        <PositionsWidget 
          positions={portfolio?.openPositions || []}
          onAction={handleAction}
          showLeverage={true}
          showMarginMode={true}
          error={closeMutation.error?.message}
        />
      </div>
      <footer className="p-2 text-xs text-gray-500 text-center">
        Last updated: {new Date().toLocaleTimeString()}
      </footer>
    </div>
  );
}

