import React, { useEffect, useMemo } from 'react';
import { MobilePositionsWidget } from '@orderly.network/ui-positions';
import { usePortfolio, usePositionClose, useAccountInfo, useWSObserver } from '@orderly.network/hooks';

export function AdvancedMobilePositions() {
  const { data: account } = useAccountInfo();
  const { data: portfolio, refetch } = usePortfolio();
  const { closePosition, isClosing } = usePositionClose();
  const { subscribe } = useWSObserver();

  const positions = useMemo(() => portfolio?.positions || [], [portfolio]);

  useEffect(() => {
    if (account?.accountId) {
      const unsub = subscribe('positions', refetch);
      return () => unsub();
    }
  }, [account, subscribe, refetch]);

  const handleAction = async (pos, action) => {
    if (action === 'close') await closePosition(pos);
  };

  return (
    <div className="full-mobile-stack">
      <header>
        <span>Account: {account?.accountId}</span>
        <span>Balance: {portfolio?.totalBalance}</span>
      </header>
      <MobilePositionsWidget
        positions={positions}
        onAction={handleAction}
        isProcessing={isClosing}
        theme="dark"
      />
      <footer>
        <button onClick={refetch}>Refresh</button>
      </footer>
    </div>
  );
}

