import React from 'react';
import { CombinePositionsWidget } from '@orderly.network/ui-positions';
import { usePortfolio, useMarginModes, useAccountInfo } from '@orderly.network/hooks';

export function RiskAwareCombinedView() {
  const { data: account } = useAccountInfo();
  const { data: portfolio } = usePortfolio();
  const { data: marginModes } = useMarginModes();

  if (!account || !portfolio) return <div>Loading...</div>;

  const enrichedPositions = portfolio.positions.map(pos => ({
    ...pos,
    marginMode: marginModes?.[pos.symbol] || 'isolated',
    leverage: pos.leverage || 1
  }));

  const summary = {
    totalEquity: portfolio.totalBalance,
    positions: enrichedPositions,
    riskLevel: enrichedPositions.length > 5 ? 'High' : 'Low'
  };

  return (
    <div className="risk-view">
      <CombinePositionsWidget 
        data={summary}
        showRiskMetrics={true}
      />
    </div>
  );
}

import React, { useState, useMemo } from 'react';
import { CombinePositionsWidget } from '@orderly.network/ui-positions';
import { usePortfolio, useAccountInfo, useMarginModes } from '@orderly.network/hooks';

export function MultiAccountCombinedView() {
  const [filter, setFilter] = useState('all');
  const { data: accounts } = useAccountInfo();
  const { data: portfolio } = usePortfolio();
  const { data: marginModes } = useMarginModes();

  const aggregated = useMemo(() => {
    if (!portfolio) return { positions: [], totalPnl: 0 };

    let pos = portfolio.positions;
    if (filter === 'profitable') {
      pos = pos.filter(p => p.pnl > 0);
    } else if (filter === 'isolated') {
      pos = pos.filter(p => marginModes?.[p.symbol] === 'isolated');
    }

    return {
      positions: pos,
      totalPnl: pos.reduce((acc, p) => acc + p.pnl, 0),
      count: pos.length
    };
  }, [portfolio, filter, marginModes]);

  const handleExport = () => {
    const csv = aggregated.positions.map(p => `${p.symbol},${p.pnl}`).join('\n');
    console.log(csv);
  };

  return (
    <div className="advanced-combine">
