import React, { useEffect, useMemo } from 'react';
import { ReversePositionWidget } from '@orderly.network/ui-positions';
import { useAccountInfo, usePositionClose, useSymbolLeverageMap } from '@orderly.network/sdk';

export default function ProReverse() {
  const { account } = useAccountInfo();
  const { closePosition } = usePositionClose();
  const { leverageMap } = useSymbolLeverageMap();
  const [leverage, setLeverage] = useState(10);

  const maxLeverage = useMemo(() => {
    return leverageMap?.['BTC-PERP']?.maxLeverage || 100;
  }, [leverageMap]);

  useEffect(() => {
    if (leverage > maxLeverage) setLeverage(maxLeverage);
  }, [leverage, maxLeverage]);

  const handleReverse = async (params) => {
    const finalParams = { ...params, leverage };
    await closePosition(finalParams);
  };

  if (!account) return <div>Connect Wallet</div>;

  return (
    <div className="p-6 bg-gray-50 rounded-lg shadow">
      <div className="mb-4">
        <label>Leverage: {leverage}x</label>
        <input 
          type="range" 
          min="1" 
          max={maxLeverage}
          value={leverage}
          onChange={(e) => setLeverage(Number(e.target.value))}
          className="w-full"
        />
      </div>
      <ReversePositionWidget 
        accountId={account.id}
        symbol="BTC-PERP"
        onConfirm={handleReverse}
        leverage={leverage}
      />
      <div className="text-xs text-gray-500 mt-2">
        Max allowed: {maxLeverage}x
      </div>
    </div>
  );
}

