const WIDGET_TABS = [
  { id: 'trade', label: 'Trade', requiresKey: true },
  { id: 'history', label: 'History', requiresKey: true },
  { id: 'settings', label: 'Settings', requiresKey: false }
];

/**
 * Advanced Widget Example
 * Handles permissions and API key validation
 */
export function WidgetAdvanced() {
  const [activeTab, setActiveTab] = useState('trade');
  const { keys, hasValidKey, addKey } = useApiKeyManager();
  const { canTrade } = useOrderEntry();

  // Force settings tab if no key
  useEffect(() => {
    if (!hasValidKey && activeTab !== 'settings') {
      setActiveTab('settings');
    }
  }, [hasValidKey, activeTab]);

  const availableTabs = useMemo(() => {
    return WIDGET_TABS.map(tab => ({
      ...tab,
      disabled: tab.requiresKey && !hasValidKey
    }));
  }, [hasValidKey]);

  const handleTabChange = (id) => {
    const tab = availableTabs.find(t => t.id === id);
    if (tab && !tab.disabled) {
      setActiveTab(id);
    }
  };

  return (
    <div className="dashboard-widget">
      <div className="widget-header">
        <span>API Status: {hasValidKey ? 'Active' : 'Inactive'}</span>
        {!hasValidKey && <button onClick={addKey}>Connect Key</button>}
      </div>
      <BottomNavWidget
        actions={availableTabs}
        activeAction={activeTab}
        onAction={handleTabChange}
        style="bordered"
      />
      <div className="widget-content">
        {activeTab === 'trade' && <TradeForm />}
        {activeTab === 'history' && <OrderHistory />}
        {activeTab === 'settings' && <ApiKeySettings />}
      </div>
    </div>
  );
}

