import React, { useEffect } from 'react';
import { OfflineInfoWidget } from '@orderly.network/ui-scaffold';
import { useApiStatusActions, useWSObserver } from '@orderly.network/hooks';

export default function CustomStatus() {
  const { status, reconnect } = useApiStatusActions();
  const { connected } = useWSObserver();

  useEffect(() => {
    if (status === 'offline') {
      console.warn('Connection lost');
    }
  }, [status]);

  const handleRetry = async () => {
    await reconnect();
  };

  return (
    <OfflineInfoWidget
      status={status}
      message={connected ? 'Live' : 'Reconnecting...'}
      onRetry={handleRetry}
      variant="banner"
    />
  );
}

import React, { useState, useCallback } from 'react';
import { OfflineInfoWidget } from '@orderly.network/ui-scaffold';
import { useApiStatusActions, useAccountInfo } from '@orderly.network/hooks';

export default function RobustStatusWidget() {
  const { status, reconnect, error } = useApiStatusActions();
  const { account } = useAccountInfo();
  const [retryCount, setRetryCount] = useState(0);

  const onRetry = useCallback(async () => {
    try {
      await reconnect();
      setRetryCount(0);
    } catch (err) {
      setRetryCount(prev => prev + 1);
      console.error('Retry failed', err);
    }
  }, [reconnect]);

  if (status === 'online') return null;

  return (
    <OfflineInfoWidget
      status={status}
      account={account}
      error={error}
      retryCount={retryCount}
      onRetry={onRetry}
      maxRetries={5}
      className="custom-offline-overlay"
    />
  );
}

