import React, { useState, useMemo } from 'react';
import { PriceInput } from '@orderly.network/ui-tpsl';
import { useOrderEntry, useAccountInfo } from '@orderly.network/sdk';

export default function SmartPriceInput({ symbol, side }) {
  const [price, setPrice] = useState('');
  const { accountBalance } = useAccountInfo();
  const { validatePrice, submitOrder, getPrecision } = useOrderEntry();

  const precision = useMemo(() => getPrecision(symbol), [symbol, getPrecision]);
  const maxBuyable = useMemo(() => {
    if (!accountBalance) return 0;
    return side === 'buy' ? accountBalance / (parseFloat(price) || 1) : 0;
  }, [accountBalance, price, side]);

  const handleChange = (val) => {
    setPrice(val);
  };

  const handleSubmit = async () => {
    const isValid = validatePrice(symbol, price);
    if (!isValid) {
      alert('Invalid price for symbol');
      return;
    }
    if (side === 'buy' && maxBuyable < 1) {
      alert('Insufficient balance');
      return;
    }
    await submitOrder({ symbol, price, side, qty: '1' });
  };

  return (
    <div style={{ border: '1px solid #ccc', padding: '16px' }}>
      <h3>Order Entry: {symbol}</h3>
      <PriceInput
        value={price}
        onChange={handleChange}
        precision={precision}
        placeholder="0.0000"
      />
      <div style={{ marginTop: '8px', fontSize: '12px' }}>
        Max Buyable: {maxBuyable.toFixed(4)}
      </div>
      <button
        onClick={handleSubmit}
        style={{ marginTop: '16px', padding: '8px 16px' }}
      >
        Confirm Order
      </button>
    </div>
  );
}

