import React, { useState, useEffect } from 'react';
import { TPSL } from '@orderly.network/ui-tpsl';
import { useOrderEntry, usePositionClose, useMarginModeBySymbol } from '@orderly.network/sdk';

export default function AdvancedTPSL({ symbol, position }) {
  const [tp, setTp] = useState('');
  const [sl, setSl] = useState('');
  const { submitOrder } = useOrderEntry();
  const { closePosition } = usePositionClose();
  const { marginMode } = useMarginModeBySymbol(symbol);

  useEffect(() => {
    if (position) {
      // Auto-calculate suggested TP/SL based on position
      const entry = position.entryPrice;
      setTp((entry * 1.05).toFixed(2));
      setSl((entry * 0.95).toFixed(2));
    }
  }, [position]);

  const handleModify = async () => {
    if (!position) return;
    await closePosition({
      symbol,
      takeProfit: tp,
      stopLoss: sl,
      marginMode,
    });
  };

  const handleNewOrder = async () => {
    await submitOrder({
      symbol,
      price: position?.entryPrice || '0',
      side: 'buy',
      qty: '1',
      takeProfit: tp,
      stopLoss: sl,
    });
  };

  return (
    <div style={{ border: '1px solid #333', padding: '16px' }}>
