import React, { useEffect, useMemo } from 'react';
import { TPSLWidget } from '@orderly.network/ui-tpsl';
import { usePortfolio, useAccountInfo, useMarginModeBySymbol } from '@orderly.network/react-hooks';
import { useTheme } from '@orderly.network/ui';

export function AdvancedTPSLWidget() {
  const { positions } = usePortfolio();
  const { account } = useAccountInfo();
  const { marginMode } = useMarginModeBySymbol(positions?.[0]?.symbol);
  const { theme } = useTheme();
  const [error, setError] = useState(null);

  const isCrossMargin = marginMode === 'CROSS';
  const hasSufficientBalance = account?.availableBalance > 0;

  useEffect(() => {
    if (!hasSufficientBalance) {
      setError('Insufficient balance for margin adjustments.');
    } else {
      setError(null);
    }
  }, [hasSufficientBalance]);

  const widgetConfig = useMemo(() => ({
    symbol: positions?.[0]?.symbol,
    side: positions?.[0]?.side,
    quantity: positions?.[0]?.quantity,
    marginMode: isCrossMargin ? 'cross' : 'isolated',
    theme: theme,
    validationRules: {
      minTp: 1.01,
      maxSl: 0.99
    }
  }), [positions, isCrossMargin, theme]);

  if (positions.length === 0) return <div>Select a position first</div>;

  return (
    <div className={`advanced-tpsl-${theme}`}>
      <header>
        <h3>Position Risk Management</h3>
        <span className="margin-badge">{isCrossMargin ? 'Cross' : 'Isolated'}</span>
      </header>
      {error && <div className="error-banner">{error}</div>}
      <TPSLWidget
        {...widgetConfig}
        onValidate={(data) => {
          if (data.slPrice >= data.entryPrice && data.side === 'LONG') return false;
          return true;
        }}
        onConfirm={(orderData) => {
          console.log('Confirming TPSL:', orderData);
        }}
      />
      <footer>
        <small>Margin Mode: {marginMode}</small>
      </footer>
    </div>
  );
}

