import React, { useState, useEffect } from 'react';
import { MobileTimeInterval } from '@orderly.network/ui-tradingview';
import { useWSObserver } from '@orderly.network/hooks';

const intervals = ['1m', '5m', '15m', '1h', '4h', '1d'];

export function DataSyncTimeInterval({ symbol }) {
  const [selected, setSelected] = useState('15m');
  const { subscribe, unsubscribe } = useWSObserver();

  useEffect(() => {
    // Refresh data when interval changes
    unsubscribe(symbol);
    subscribe(symbol, { interval: selected });
    return () => unsubscribe(symbol);
  }, [selected, symbol, subscribe, unsubscribe]);

  const handleSelect = (interval) => {
    setSelected(interval);
  };

  return (
    <div className="p-4 bg-gray-900 border border-gray-800 rounded-lg">
      <MobileTimeInterval
        intervals={intervals}
        selected={selected}
        onSelect={handleSelect}
      />
      <div className="mt-2 text-xs text-green-500">
        Live Data: {selected}
      </div>
    </div>
  );
}

