import React, { useMemo } from 'react';
import { CollateralRatioUI } from '@orderly.network/ui-transfer';
import { usePortfolio, useMarginModes, useSymbolLeverageMap } from '@orderly.network/sdk';

export default function AdvancedRatio() {
  const { portfolio } = usePortfolio();
  const { marginMode } = useMarginModes();
  const { leverageMap } = useSymbolLeverageMap();

  const positions = portfolio?.positions || {};
  const totalRatio = useMemo(() => {
    const ratios = Object.values(positions).map(p => p.collateralRatio || 0);
    return ratios.length ? ratios.reduce((a, b) => a + b, 0) / ratios.length : 0;
  }, [positions]);

  const riskLevel = useMemo(() => {
    if (totalRatio < 1.1) return 'Critical';
    if (totalRatio < 1.3) return 'Warning';
    return 'Safe';
  }, [totalRatio]);

  const riskColor = useMemo(() => {
    if (riskLevel === 'Critical') return 'bg-red-500';
    if (riskLevel === 'Warning') return 'bg-yellow-500';
    return 'bg-green-500';
  }, [riskLevel]);

  return (
    <div className="p-8 bg-gray-100 min-h-screen">
      <div className="max-w-5xl mx-auto">
        <header className="mb-8">
          <h1 className="text-3xl font-bold text-gray-800">Risk Dashboard</h1>
          <div className="flex items-center mt-2">
            <span className={`w-3 h-3 rounded-full mr-2 ${riskColor}`}></span>
            <span className="text-lg font-medium">{riskLevel} Risk</span>
            <span className="ml-4 text-sm text-gray-500">Mode: {marginMode}</span>
          </div>
        </header>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          {Object.entries(positions).map(([symbol, pos]) => (
            <div key={symbol} className="bg-white p-4 rounded shadow">
              <div className="flex justify-between items-start mb-2">
                <h3 className="font-bold text-lg">{symbol}</h3>
                <span className="text-xs bg-gray-200 px-2 py-1 rounded">
                  {leverageMap?.[symbol] || 10}x
