export function CollateralRatioWidgetStandard() {
  const { data: portfolio } = usePortfolio();

  if (!portfolio) return <div>Loading...</div>;

  const ratio = portfolio.equity / (portfolio.marginUsed || 1);
  const isLow = ratio < 1.5;
  const isCritical = ratio < 1.2;

  const getColor = () => {
    if (isCritical) return 'red';
    if (isLow) return 'orange';
    return 'green';
  };

  const progress = Math.min((ratio / 3) * 100, 100);

  return (
    <div className="ratio-widget-standard">
      <div className="header">
        <span>Ratio</span>
        <span style={{ color: getColor() }}>{ratio.toFixed(2)}x</span>
      </div>
      <div className="bar-container">
        <div 
          className="bar-fill" 
          style={{ width: `${progress}%`, backgroundColor: getColor() }}
        />
      </div>
      <div className="status">
        {isCritical ? 'Critical Risk' : isLow ? 'Low Margin' : 'Healthy'}
      </div>
    </div>
  );
}

