import React, { useState, useEffect } from 'react';
import { DepositStatus } from '@orderly.network/ui-transfer';
import { useTransferHistory, useWSObserver } from '@orderly.network/react';

export default function RealtimeDepositMonitor() {
  const [activeDeposit, setActiveDeposit] = useState(null);
  const { data: history } = useTransferHistory({ type: 'deposit', limit: 5 });

  // Simulate WebSocket subscription for deposit updates
  const { data: wsData } = useWSObserver({
    channel: 'deposit_updates',
    enabled: !!activeDeposit
  });

  useEffect(() => {
    if (history && history.length > 0) {
      setActiveDeposit(history[0]);
    }
  }, [history]);

  useEffect(() => {
    if (wsData && activeDeposit) {
      // Update local state if WS confirms new block
      setActiveDeposit(prev => ({ ...prev, status: wsData.status }));
    }
  }, [wsData, activeDeposit]);

  if (!activeDeposit) return <div className="p-4">Waiting for deposit...</div>;

  const progress = Math.min(
    (activeDeposit.confirmations / activeDeposit.required_confirmations) * 100,
    100
  );

  return (
    <div className="p-6 bg-gray-50 rounded-xl border">
      <div className="flex justify-between items-center mb-4">
        <h3 className="text-lg font-bold">Deposit Monitor</h3>
        <span className={`px-2 py-1 rounded text-xs ${
          activeDeposit.status === 'confirmed' ? 'bg-green-100 text-green-800' : 'bg-yellow-100 text-yellow-800'
        }`}>
          {activeDeposit.status.toUpperCase()}
        </span>
      </div>

      <DepositStatus
        status={activeDeposit.status}
        confirmations={activeDeposit.confirmations}
        required={activeDeposit.required_confirmations}
        asset={activeDeposit.asset}
        showProgressBar={true}
      />

      <div className="mt-4 w-full bg-gray-200 rounded-full h-2.5">
        <div 
          className="bg-blue-600 h-2.5 rounded-full transition-all duration-500"
          style={{ width: `${progress}%` }}
        ></div>
      </div>
      <p className="text-xs text-center mt-2 text-gray-500">
        {progress.toFixed(0)}% Confirmed
      </p>

      <div className="mt-4 text-sm text-gray-600">
        Hash: <span className="font-mono">{activeDeposit.tx_hash}</span>
      </div>
    </div>
  );
}

