  }, [account, rate, slippage]);

  const isLowBalance = useMemo(() => {
    const balance = portfolio?.find(p => p.asset === 'ETH')?.amount || 0;
    return balance < inputAmount;
  }, [portfolio, inputAmount]);

  return (
    <div className="p-4 border rounded-lg">
      <div className="flex justify-between mb-2">
        <span className="font-medium">Minimum Received</span>
        {isLowBalance && (
          <span className="text-red-500 text-xs">Insufficient Balance</span>
        )}
      </div>
      <MinimumReceived
        amount={`${minReceived} ETH`}
        slippage="0.5%"
        fees="0.002 ETH"
        warning={isLowBalance ? 'Not enough funds' : undefined}
        onConfirm={() => console.log('Confirmed')}
      />
    </div>
  );
}

