import React, { useState, useEffect, useCallback } from 'react';
import { WithdrawForm } from '@orderly.network/ui-transfer';
import { usePortfolio, useAccountInfo } from '@orderly.network/hooks';

export function WithdrawalAdvanced() {
  const { assets, isLoading: portfolioLoading } = usePortfolio();
  const { balance, isLoading: accountLoading } = useAccountInfo();
  const [selectedAsset, setSelectedAsset] = useState('');
  const [amount, setAmount] = useState('');
  const [error, setError] = useState(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  useEffect(() => {
    if (assets.length > 0 && !selectedAsset) {
      setSelectedAsset(assets[0].symbol);
    }
  }, [assets, selectedAsset]);

  const validateAmount = useCallback((val) => {
    const assetBalance = balance.find(b => b.symbol === selectedAsset);
    if (!assetBalance) return true;
    if (parseFloat(val) > parseFloat(assetBalance.available)) {
      setError('Insufficient balance');
      return false;
    }
    setError(null);
    return true;
  }, [balance, selectedAsset]);

  const handleAmountChange = (val) => {
    setAmount(val);
    validateAmount(val);
  };

  const handleSubmit = async (data) => {
    if (!validateAmount(data.amount)) return;
    setIsSubmitting(true);
    try {
      // Simulate API call
      await new Promise(r => setTimeout(r, 1000));
      console.log('Success:', data);
    } catch (err) {
      setError('Transaction failed');
    } finally {
      setIsSubmitting(false);
    }
  };

  if (portfolioLoading || accountLoading) {
    return <div>Loading account data...</div>;
  }

  return (
    <div className="p-4 border rounded shadow max-w-md">
      <h2 className="text-lg font-bold mb-4">Withdraw Assets</h2>
      {error && <div className="text-red-500 mb-2">{error}</div>}
      <WithdrawForm
        asset={selectedAsset}
        amount={amount}
        onAssetChange={setSelectedAsset}
        onAmountChange={handleAmountChange}
        onSubmit={handleSubmit}
        disabled={isSubmitting}
        availableAssets={assets}
        showBalance={true}
      />
    </div>
  );
}

