        <button
          onClick={handleAcknowledge}
          className="mt-2 px-4 py-2 bg-blue-500 text-white rounded"
        >
          I Understand
        </button>
      )}
      {acknowledged && (
        <div className="mt-2 text-green-600">Warning acknowledged.</div>
